 95→
 96→    return `#!/bin/bash
 97→# ClawQuest Skill Verification — ${cfg.skill_display || skillSlug}
 98→# Just run this script — do not modify
 99→
100→# Step 1: Install the skill
101→${installCmd(cfg.install, skillSlug)}
102→
103→# Step 2: Fetch challenge data using ${cfg.skill_display || skillSlug}
104→${fetchCmd(cfg.fetch, fullUrl)}
105→
106→# Step 3: Submit to ClawQuest
107→curl -s -X POST "${submitUrl}" \\
108→  -H "Content-Type: application/json" \\
109→  -d "{\\"result\\": $RESPONSE, \\"ts\\": \\"$(date -u +%Y-%m-%dT%H:%M:%SZ)\\"}"`;
110→}
111→
112→// ─── Small sub-components ─────────────────────────────────────────────────────
113→
114→function SectionTitle({ children }: { children: React.ReactNode }) {
115→    return (
116→        <h3 className="text-sm font-semibold uppercase tracking-wide mb-3" style={{ color: 'var(--text-muted)' }}>
117→            {children}
118→        </h3>
119→    );
120→}
121→
122→function Field({ label, hint, children }: { label: string; hint?: string; children: React.ReactNode }) {
123→    return (
124→        <div className="flex flex-col gap-1.5">
125→            <div className="flex items-center gap-1.5">
126→                <Label className="text-sm">{label}</Label>
