136→}
137→
138→// ─── Section: Basic ───────────────────────────────────────────────────────────
139→
140→function BasicSection({ value, onChange }: { value: VerificationConfigValue; onChange: (v: VerificationConfigValue) => void }) {
141→    return (
142→        <div className="flex flex-col gap-4">
143→            <SectionTitle>Basic</SectionTitle>
144→            <Field label="Skill Display Name" hint="Shown in the verification challenge markdown">
145→                <Input
146→                    value={value.skill_display}
147→                    onChange={e => onChange({ ...value, skill_display: e.target.value })}
148→                    placeholder="e.g. Bybit Trading"
149→                />
150→            </Field>
151→            <Field label="Task Description" hint="Describes what the agent must do. Use ${variable} for dynamic parts.">
152→                <textarea
153→                    className="w-full rounded-md border text-sm px-3 py-2 min-h-[72px] resize-y focus:outline-none focus:ring-2 focus:ring-ring"
154→                    style={{ background: 'var(--bg-base)', borderColor: 'var(--border)', color: 'var(--text-primary)' }}
155→                    value={value.task_description}
156→                    onChange={e => onChange({ ...value, task_description: e.target.value })}
157→                    placeholder="e.g. Fetch spot kline data for ${symbol} from Bybit API"
158→                />
159→            </Field>
160→        </div>
161→    );
162→}
163→
164→// ─── Section: Install ─────────────────────────────────────────────────────────
165→
166→const INSTALL_TYPES: { value: InstallType; label: string; desc: string }[] = [
167→    { value: 'npx_clawhub', label: 'npx clawhub (default)', desc: 'npx clawhub@latest install <slug>' },
168→    { value: 'npx_package', label: 'npx package', desc: 'npx <package>@<version>' },
169→    { value: 'pip', label: 'pip', desc: 'pip install <package>' },
170→    { value: 'npm_global', label: 'npm global', desc: 'npm install -g <package>' },
171→    { value: 'brew', label: 'brew', desc: 'brew install <package>' },
172→    { value: 'custom', label: 'custom', desc: 'Full command template' },
173→];
174→
175→function InstallSection({ value, onChange, skillSlug }: {
176→    value: VerificationConfigValue;
177→    onChange: (v: VerificationConfigValue) => void;
178→    skillSlug: string;
179→}) {
180→    const install = value.install;
181→    const setInstall = (i: InstallConfig) => onChange({ ...value, install: i });
182→
183→    return (
184→        <div className="flex flex-col gap-4">
185→            <SectionTitle>Install Configuration</SectionTitle>
186→            <Field label="Install Method">
187→                <select
188→                    className="w-full rounded-md border text-sm px-3 py-2 focus:outline-none focus:ring-2 focus:ring-ring"
189→                    style={{ background: 'var(--bg-base)', borderColor: 'var(--border)', color: 'var(--text-primary)' }}
190→                    value={install.type}
191→                    onChange={e => setInstall({ ...install, type: e.target.value as InstallType })}
192→                >
193→                    {INSTALL_TYPES.map(t => (
194→                        <option key={t.value} value={t.value}>{t.label} — {t.desc}</option>
195→                    ))}
196→                </select>
197→            </Field>
198→
199→            {install.type !== 'npx_clawhub' && install.type !== 'custom' && (
200→                <Field label="Package Name" hint="Leave empty to use the skill slug">
201→                    <Input
202→                        value={install.package ?? ''}
203→                        onChange={e => setInstall({ ...install, package: e.target.value || undefined })}
204→                        placeholder={`defaults to "${skillSlug}"`}
205→                    />
206→                </Field>
207→            )}
208→
209→            {install.type === 'npx_package' && (
210→                <Field label="Version" hint="e.g. 'latest', '1.2.3'. Defaults to latest.">
211→                    <Input
212→                        value={install.version ?? ''}
213→                        onChange={e => setInstall({ ...install, version: e.target.value || undefined })}
214→                        placeholder="latest"
215→                    />
216→                </Field>
217→            )}
218→
219→            {install.type === 'custom' && (
220→                <Field label="Custom Command" hint="Use ${package} as placeholder for the package name">
221→                    <textarea
222→                        className="w-full rounded-md border text-sm px-3 py-2 min-h-[64px] font-mono resize-y focus:outline-none focus:ring-2 focus:ring-ring"
223→                        style={{ background: 'var(--bg-base)', borderColor: 'var(--border)', color: 'var(--text-primary)' }}
224→                        value={install.command ?? ''}
225→                        onChange={e => setInstall({ ...install, command: e.target.value })}
226→                        placeholder="e.g. curl -fsSL https://example.com/install.sh | sh"
227→                    />
228→                </Field>
229→            )}
230→
231→            <div className="rounded-md px-3 py-2 text-xs font-mono" style={{ background: 'var(--bg-tertiary)', color: 'var(--text-secondary)' }}>
232→                <span className="opacity-50 mr-2">#</span>
233→                {installCmd(install, skillSlug) || '…'}
234→            </div>
235→        </div>
236→    );
237→}
238→
239→// ─── Section: Fetch ───────────────────────────────────────────────────────────
240→
241→const FETCH_TYPES: { value: FetchType; label: string }[] = [
242→    { value: 'curl', label: 'curl (default)' },
243→    { value: 'wget', label: 'wget' },
244→    { value: 'custom', label: 'custom' },
245→];
246→
247→function FetchSection({ value, onChange }: { value: VerificationConfigValue; onChange: (v: VerificationConfigValue) => void }) {
248→    const fetch = value.fetch;
249→    const setFetch = (f: FetchConfig) => onChange({ ...value, fetch: f });
250→
251→    return (
252→        <div className="flex flex-col gap-4">
253→            <SectionTitle>Fetch Configuration</SectionTitle>
254→            <Field label="Fetch Method">
255→                <select
256→                    className="w-full rounded-md border text-sm px-3 py-2 focus:outline-none focus:ring-2 focus:ring-ring"
257→                    style={{ background: 'var(--bg-base)', borderColor: 'var(--border)', color: 'var(--text-primary)' }}
258→                    value={fetch.type}
259→                    onChange={e => setFetch({ ...fetch, type: e.target.value as FetchType })}
260→                >
261→                    {FETCH_TYPES.map(t => (
262→                        <option key={t.value} value={t.value}>{t.label}</option>
263→                    ))}
264→                </select>
265→            </Field>
266→
267→            {fetch.type === 'custom' && (
268→                <Field label="Custom Command" hint="Use ${url} as placeholder for the full API URL">
269→                    <textarea
270→                        className="w-full rounded-md border text-sm px-3 py-2 min-h-[64px] font-mono resize-y focus:outline-none focus:ring-2 focus:ring-ring"
271→                        style={{ background: 'var(--bg-base)', borderColor: 'var(--border)', color: 'var(--text-primary)' }}
272→                        value={fetch.command ?? ''}
273→                        onChange={e => setFetch({ ...fetch, command: e.target.value })}
274→                        placeholder="RESPONSE=$(curl -s &quot;${url}&quot;)"
275→                    />
276→                </Field>
277→            )}
278→
279→            <div className="rounded-md px-3 py-2 text-xs font-mono" style={{ background: 'var(--bg-tertiary)', color: 'var(--text-secondary)' }}>
280→                <span className="opacity-50 mr-2">#</span>
281→                {fetchCmd(fetch, '<url>')}
282→            </div>
283→        </div>
284→    );
285→}
286→
287→// ─── Section: API + Params ────────────────────────────────────────────────────
288→
289→function ApiSection({ value, onChange }: { value: VerificationConfigValue; onChange: (v: VerificationConfigValue) => void }) {
290→    const paramEntries = Object.entries(value.params);
291→
292→    function setParam(oldKey: string, newKey: string, val: string) {
293→        const next: Record<string, string> = {};
294→        for (const [k, v] of Object.entries(value.params)) {
295→            if (k === oldKey) {
296→                if (newKey) next[newKey] = val;
297→            } else {
298→                next[k] = v;
299→            }
300→        }
301→        onChange({ ...value, params: next });
302→    }
303→
304→    function addParam() {
305→        onChange({ ...value, params: { ...value.params, '': '' } });
306→    }
307→
308→    function removeParam(key: string) {
309→        const next = { ...value.params };
310→        delete next[key];
311→        onChange({ ...value, params: next });
312→    }
313→
314→    return (
315→        <div className="flex flex-col gap-4">
316→            <SectionTitle>API Endpoint & Parameters</SectionTitle>
317→            <Field label="API Endpoint URL">
318→                <Input
319→                    value={value.api_endpoint}
320→                    onChange={e => onChange({ ...value, api_endpoint: e.target.value })}
321→                    placeholder="https://api.example.com/v5/market/kline"
322→                />
323→            </Field>
324→
325→            <div className="flex flex-col gap-2">
326→                <div className="flex items-center justify-between">
327→                    <Label className="text-sm">Query Parameters</Label>
328→                    <Button variant="outline" size="sm" onClick={addParam} className="gap-1 h-7 text-xs">
329→                        <Plus size={12} /> Add Param
330→                    </Button>
331→                </div>
332→                <p className="text-xs" style={{ color: 'var(--text-muted)' }}>
333→                    Values can reference variables using <code className="font-mono bg-muted px-1 rounded">{'${variable}'}</code>
334→                </p>
335→                {paramEntries.length === 0 && (
336→                    <div className="text-xs py-3 text-center rounded-md" style={{ color: 'var(--text-muted)', background: 'var(--bg-tertiary)' }}>
337→                        No parameters yet
338→                    </div>
339→                )}
340→                {paramEntries.map(([k, v], i) => (
341→                    <div key={i} className="flex items-center gap-2">
342→                        <Input
343→                            className="flex-1 font-mono text-xs"
344→                            value={k}
345→                            onChange={e => setParam(k, e.target.value, v)}
346→                            placeholder="param name"
347→                        />
348→                        <Input
349→                            className="flex-1 font-mono text-xs"
350→                            value={v}
351→                            onChange={e => setParam(k, k, e.target.value)}
352→                            placeholder="value or ${variable}"
353→                        />
354→                        <Button variant="ghost" size="sm" onClick={() => removeParam(k)} className="shrink-0 text-destructive hover:text-destructive">
355→                            <Trash2 size={14} />
356→                        </Button>
357→                    </div>
358→                ))}
359→            </div>
360→        </div>
361→    );
362→}
363→
364→// ─── Section: Variables ───────────────────────────────────────────────────────
365→
366→function VariablesSection({ value, onChange }: { value: VerificationConfigValue; onChange: (v: VerificationConfigValue) => void }) {
367→    const varEntries = Object.entries(value.variable_options);
368→
369→    function setVar(oldKey: string, newKey: string, options: string[]) {
370→        const next: Record<string, string[]> = {};
371→        for (const [k, v] of Object.entries(value.variable_options)) {
372→            if (k === oldKey) {
373→                if (newKey) next[newKey] = options;
374→            } else {
375→                next[k] = v;
376→            }
377→        }
378→        onChange({ ...value, variable_options: next });
379→    }
380→
381→    function addVar() {
382→        onChange({ ...value, variable_options: { ...value.variable_options, '': [] } });
383→    }
384→
385→    function removeVar(key: string) {
386→        const next = { ...value.variable_options };
387→        delete next[key];
388→        onChange({ ...value, variable_options: next });
389→    }
390→
391→    return (
392→        <div className="flex flex-col gap-4">
393→            <SectionTitle>Variable Options</SectionTitle>
394→            <p className="text-xs -mt-2" style={{ color: 'var(--text-muted)' }}>
395→                Define variables referenced in params. The challenge system picks a random value for each variable per attempt.
396→            </p>
397→            <div className="flex flex-col gap-3">
398→                <div className="flex justify-end">
399→                    <Button variant="outline" size="sm" onClick={addVar} className="gap-1 h-7 text-xs">
400→                        <Plus size={12} /> Add Variable
401→                    </Button>
402→                </div>
403→                {varEntries.length === 0 && (
404→                    <div className="text-xs py-3 text-center rounded-md" style={{ color: 'var(--text-muted)', background: 'var(--bg-tertiary)' }}>
405→                        No variables defined
406→                    </div>
407→                )}
408→                {varEntries.map(([k, options], i) => (
409→                    <div key={i} className="rounded-lg border p-3 flex flex-col gap-2" style={{ borderColor: 'var(--border)', background: 'var(--bg-base)' }}>
410→                        <div className="flex items-center gap-2">
411→                            <span className="text-xs font-mono shrink-0" style={{ color: 'var(--text-muted)' }}>$&#123;</span>
412→                            <Input
413→                                className="flex-1 font-mono text-xs"
414→                                value={k}
415→                                onChange={e => setVar(k, e.target.value, options)}
416→                                placeholder="variable_name"
417→                            />
418→                            <span className="text-xs font-mono shrink-0" style={{ color: 'var(--text-muted)' }}>&#125;</span>
419→                            <Button variant="ghost" size="sm" onClick={() => removeVar(k)} className="shrink-0 text-destructive hover:text-destructive">
420→                                <Trash2 size={14} />
421→                            </Button>
422→                        </div>
423→                        <div className="flex flex-col gap-1">
424→                            <Label className="text-xs" style={{ color: 'var(--text-muted)' }}>Options (comma-separated)</Label>
425→                            <Input
426→                                className="text-xs font-mono"
427→                                value={options.join(', ')}
428→                                onChange={e => setVar(k, k, e.target.value.split(',').map(s => s.trim()).filter(Boolean))}
429→                                placeholder="BTCUSDT, ETHUSDT, DOGEUSDT"
430→                            />
431→                            {options.length > 0 && (
432→                                <div className="flex flex-wrap gap-1 mt-1">
433→                                    {options.map((opt, j) => (
434→                                        <span key={j} className="text-[10px] px-1.5 py-0.5 rounded font-mono"
435→                                            style={{ background: 'var(--bg-tertiary)', color: 'var(--text-secondary)' }}>
436→                                            {opt}
437→                                        </span>
438→                                    ))}
439→                                </div>
440→                            )}
441→                        </div>
442→                    </div>
443→                ))}
444→            </div>
445→        </div>
446→    );
447→}
448→
449→// ─── Section: Submission Fields ───────────────────────────────────────────────
450→
451→function SubmissionSection({ value, onChange }: { value: VerificationConfigValue; onChange: (v: VerificationConfigValue) => void }) {
452→    const [draft, setDraft] = useState('');
453→
454→    function addField() {
455→        const trimmed = draft.trim();
456→        if (!trimmed || value.submission_fields.includes(trimmed)) return;
457→        onChange({ ...value, submission_fields: [...value.submission_fields, trimmed] });
458→        setDraft('');
459→    }
460→
461→    function removeField(field: string) {
462→        onChange({ ...value, submission_fields: value.submission_fields.filter(f => f !== field) });
463→    }
464→
465→    return (
466→        <div className="flex flex-col gap-4">
467→            <SectionTitle>Submission Fields</SectionTitle>
468→            <p className="text-xs -mt-2" style={{ color: 'var(--text-muted)' }}>
469→                JSON fields the agent must submit. Used to validate the response.
470→            </p>
471→            <div className="flex gap-2">
472→                <Input
473→                    className="text-sm font-mono"
474→                    value={draft}
475→                    onChange={e => setDraft(e.target.value)}
476→                    onKeyDown={e => { if (e.key === 'Enter') { e.preventDefault(); addField(); } }}
477→                    placeholder="e.g. result"
478→                />
479→                <Button variant="outline" onClick={addField} className="shrink-0">
480→                    <Plus size={14} />
481→                </Button>
482→            </div>
483→            {value.submission_fields.length > 0 && (
484→                <div className="flex flex-wrap gap-2">
485→                    {value.submission_fields.map(f => (
486→                        <span key={f} className="flex items-center gap-1.5 text-sm font-mono px-2.5 py-1 rounded-md border"
487→                            style={{ borderColor: 'var(--border)', background: 'var(--bg-tertiary)', color: 'var(--text-secondary)' }}>
488→                            {f}
489→                            <button onClick={() => removeField(f)} className="opacity-50 hover:opacity-100 transition-opacity">
490→                                <Trash2 size={11} />
491→                            </button>
492→                        </span>
493→                    ))}
494→                </div>
495→            )}
496→        </div>
497→    );
498→}
499→
500→// ─── Section: Validation ──────────────────────────────────────────────────────
501→
502→function ValidationSection({ value, onChange }: { value: VerificationConfigValue; onChange: (v: VerificationConfigValue) => void }) {
503→    const val = value.validation;
504→    const setVal = (v: ValidationConfig) => onChange({ ...value, validation: v });
505→
506→    return (
507→        <div className="flex flex-col gap-4">
508→            <SectionTitle>Validation</SectionTitle>
509→            <Field label="Validation Type">
510→                <select
511→                    className="w-full rounded-md border text-sm px-3 py-2 focus:outline-none focus:ring-2 focus:ring-ring"
512→                    style={{ background: 'var(--bg-base)', borderColor: 'var(--border)', color: 'var(--text-primary)' }}
513→                    value={val.type}
514→                    onChange={e => setVal({ ...val, type: e.target.value as ValidationConfig['type'] })}
515→                >
516→                    <option value="non_empty_response">non_empty_response — response must not be empty/null</option>
517→                    <option value="field_exists">field_exists — a specific JSON field must exist in the response</option>
518→                    <option value="custom">custom — manual validation (no automated check)</option>
519→                </select>
520→            </Field>
521→            {val.type === 'field_exists' && (
522→                <Field label="Check Path" hint="Dot-separated JSON path, e.g. result.0.open">
523→                    <Input
524→                        value={val.check_path ?? ''}
525→                        onChange={e => setVal({ ...val, check_path: e.target.value })}
526→                        placeholder="e.g. result"
527→                    />
528→                </Field>
529→            )}
530→        </div>
531→    );
532→}
533→
534→// ─── Main Form ────────────────────────────────────────────────────────────────
535→
536→interface Props {
537→    skillSlug: string;
538→    value: VerificationConfigValue;
539→    onChange: (v: VerificationConfigValue) => void;
540→}
541→
542→export function VerificationConfigForm({ skillSlug, value, onChange }: Props) {
543→    const preview = buildPreviewScript(value, skillSlug);
544→
545→    const handleChange = useCallback((v: VerificationConfigValue) => {
546→        onChange(v);
547→    }, [onChange]);
548→
549→    return (
550→        <div className="flex gap-6">
551→            {/* Left: form panels */}
552→            <div className="flex-1 min-w-0 flex flex-col gap-6">
553→                {/* Panel */}
554→                {[
555→                    <BasicSection key="basic" value={value} onChange={handleChange} />,
556→                    <InstallSection key="install" value={value} onChange={handleChange} skillSlug={skillSlug} />,
557→                    <FetchSection key="fetch" value={value} onChange={handleChange} />,
558→                    <ApiSection key="api" value={value} onChange={handleChange} />,
559→                    <VariablesSection key="vars" value={value} onChange={handleChange} />,
560→                    <SubmissionSection key="submit" value={value} onChange={handleChange} />,
561→                    <ValidationSection key="validation" value={value} onChange={handleChange} />,
562→                ].map((section, i) => (
563→                    <div key={i} className="rounded-xl border p-5" style={{ borderColor: 'var(--border)', background: 'var(--bg-secondary)' }}>
564→                        {section}
565→                    </div>
566→                ))}
567→            </div>
568→
569→            {/* Right: live preview */}
570→            <div className="w-[380px] shrink-0 sticky top-6 self-start">
571→                <div className="rounded-xl border overflow-hidden" style={{ borderColor: 'var(--border)' }}>
572→                    <div className="flex items-center justify-between px-4 py-2.5 border-b" style={{ borderColor: 'var(--border)', background: 'var(--bg-tertiary)' }}>
573→                        <span className="text-xs font-semibold uppercase tracking-wide" style={{ color: 'var(--text-muted)' }}>
574→                            Script Preview
575→                        </span>
576→                        <span className="text-[10px] px-1.5 py-0.5 rounded" style={{ background: 'var(--bg-secondary)', color: 'var(--text-muted)' }}>
577→                            Live
578→                        </span>
579→                    </div>
580→                    <pre
581→                        className="text-[11px] font-mono leading-relaxed p-4 overflow-auto max-h-[calc(100vh-160px)]"
582→                        style={{ background: 'var(--bg-base)', color: 'var(--text-secondary)', whiteSpace: 'pre-wrap', wordBreak: 'break-all' }}
583→                    >
584→                        {preview}
585→                    </pre>
586→                </div>
587→            </div>
588→        </div>
589→    );
590→}
